using ChatGPTImageOrchestrator.Application.Common.Interfaces; namespace ChatGPTImageOrchestrator.Application.Services; public class LimitDetectorService : ILimitDetectorService { private static readonly string[] Markers=["limit","too many images","исчерпали лимит","слишком много изображений"]; public bool IsLimitMessage(string text)=>Markers.Any(m=>text.Contains(m,StringComparison.OrdinalIgnoreCase)); }
